@module dataStore  src=dataStore.lua  loc=184  sha=fe0f215  mode=chunk  self=ds
@deps ps

# Invariants & contracts
  @invariant  per-key document storage over pextStore; each name lives at one scope (no tier merge)
  @invariant  the registry is sole truth for valid names + their scope; unknown names raise on every entry point
  @invariant  owns its cache: reads deep-clone out, writes deep-clone in; callers never alias ds state
  @invariant  take/track caches drop on pextStore contextChanged and reload lazily; project/global are context-free
  @contract  take/track scopes are per-key P_EXT blobs (ctm_data.<name>); global is one disk file (continuum-data.lua)

# Imports
  @require util = 'util'  @ 10
      @reaper  none directly; storage + undo watcher are delegated to pextStore

# Private state
  @state ps = assert(deps and deps.ps, 'dataStore requires a pextStore ...  @ 13
  @state registry = {  @ 20
  @state GLOBAL_SLOT = 'data'  @ 37
  @state cache = { take = nil, track = nil, project = nil, global = nil }  @ 60
  @state ds = {}  @ 101
  @state fire = util.installHooks(ds)  @ 102
  @state watched = {}  @ 115

# Private functions
  @fn print(...)  @ 15
  -- REGISTRY
  @fn slotFor(scope, name)  @ 41-45
      -- take/track keep one P_EXT slot per name for write isolation + per-key undo
      -- baselines; project reuses the engine's projext section with slot = name.
  @fn checkName(name)  @ 47-49
  @fn copy(v)  @ 51-54
  -- CACHE
  @fn loadScope(scope)  @ 64-77
      -- Tolerant: a stale name in the global file (post-rename) is dropped, not raised
      -- (mirrors cm's pruneUnknown). Per-key blobs can't accrue unknowns -- skip them.
  @fn ensureScope(scope)  @ 79-81
  @fn persist(scope, name, value)  @ 85-97
      -- util.REMOVE clears the slot. take/track writes are loud if unbound (document
      -- data isn't recomputable, unlike configManager's silent take-tier skip).

# Public API (ds:*)
  -- PUBLIC INTERFACE
  -- Watcher
  -- Reading
  @api ds:get(name)  @ 134-139
      @contract  returns a deep copy of the value at name's registry scope; nil if absent; raises on unknown name
  @api ds:getAt(handle, name)  @ 142-146
      -- Foreign-handle read: bypasses bound context; scope (take/track) from the registry.
  -- Writing
  @api ds:assign(name, value)  @ 151-164
      @contract  writes one key at its registry scope; util.REMOVE deletes; fires dataChanged { scope, name }
  @api ds:delete(name)  @ 166
  @api ds:assignAt(handle, name, value)  @ 170-182
      -- Foreign-handle write; util.REMOVE deletes. Refreshes the cache + signals only for
      -- the bound handle, so a write aimed at another take/track doesn't disturb the view.

